var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`앗, 이게 뭔가요? 생일파티? 킁-킁- 맛있는 냄새는 안 나는데.`,JPN:`えっと、これは何ですか？誕生日パーティー？くん、くん。美味しい匂いはしないけど。`,ENG:`Ah, what's this? A birthday party? *Sniff, Sniff* I don't smell any food.`,TWN:`啊，這是什麼？生日派對？嗅、嗅……但聞起來沒有什麼好吃的味道啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`아하, 종신계약이었어요?`,JPN:`あっ、終身契約のことですか？`,ENG:`Ah, a lifetime contract.`,TWN:`噢，終身契約嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`좋아요. 할게요, 종신계약!`,JPN:`いいですよ。終身契約、します！`,ENG:`Sure, I'll sign a lifetime contract.`,TWN:`好啊，我會簽訂終身契約的！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`사장님은 세상을 위해 좋은 일도 많이 하시고, 직원들도 많은데 저 같은 평범한 사람도 늘 챙겨 주시잖아요?`,JPN:`社長は世界のためにいいことをたくさんしてますし、会社の社員たちもたくさんいるのに、私のような普通の人のことも気にかけてくれるじゃないですか？`,ENG:`You're doing many great things for the world, and always remember to take care of run-of-the-mill employees like me.`,TWN:`老闆為這個世界做了許多好事，而且明明有很多員工，卻經常照顧我這種平凡的人、對吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`주변 사람들은 제가 생각을 너무 안 한다고 그러지만, 이런 기회는 정말 고민할 필요가 없다고요.`,JPN:`周りの人たちは私に考えなさすぎだと言ってますが、こんなチャンスは悩む必要なんてありません。`,ENG:`People around me say that I should give things more thought, but what do I have to think about such a great offer like this?`,TWN:`身邊的人常說我不動腦袋，但這種機會真的不需要擔心什麼。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`그리고 사실, 원래는 제가 먼저 사장님께 고백하려고 했는데...... 이렇게 먼저 받게 될 줄은 몰랐어요.`,JPN:`それに、実は私から社長に言おうとしてたんですが……こうして先に言われるとは思ってなかったです。`,ENG:`As a matter of fact, I was going to ask you for this, and you beat me to it.`,TWN:`況且，其實我本想先跟老闆告白的……但沒想到會被老闆搶先了一步。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`헤헤, 역시 살다 보면 종종 이런 운 좋은 날도 있는 거네요?`,JPN:`へへ、やっぱり生きていれば、たまにはこんな運のいい日もあるんですね。`,ENG:`Heh heh. Maybe today's my lucky day.`,TWN:`嘿嘿，果然活著就會有好事發生吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};